  ('social-worker-moex-05067', 'social-worker', 'social-worker-moex-107-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '王老先生已經退休多年，平日足不出戶，只愛搬一張板凳坐在家門口看著來往的人潮與車潮，對 公共事務漠不關心，遇有朋友邀約旅遊一概拒絕，與其年輕時的性格有極大轉變。王老先生的心 態符合下列那一種理論的描述？', '["脫離理論（disengagement theory）", "連續理論（continuity theory）", "社會建構理論（social construction theory）", "社會交換理論（social exchange theory）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:29+00:00", "source_pdf_sha1": "72531ff92f90", "answer_pdf_sha1": "fbf916b39630", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 35, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
